transform_js:
const axisData = []; const values = [];
rawData.rows.forEach(r => {
  axisData.push(r.time);
  values.push(r.value);
});
// Threshold for danger is 150 degrees
transformedData = { axisData, values, threshold: 150 };

echarts_js:
option = {
  title: {
    text: 'Quantum Reactor Core Temperature (°C)',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis'
  },
  grid: { left: '8%', right: '10%', bottom: '15%', containLabel: true },
  xAxis: {
    type: 'category',
    boundaryGap: false,
    data: transformedData.axisData
  },
  yAxis: {
    type: 'value',
    name: 'Temp (°C)',
    min: 50,
    max: 200
  },
  // VisualMapを用いた値に基づく色の分断
  visualMap: {
    type: 'piecewise',
    show: false,
    dimension: 1,
    pieces: [
      { min: 0, max: transformedData.threshold, color: '#314656' },
      { min: transformedData.threshold, max: 9999, color: '#cc0033' }
    ]
  },
  series: [
    {
      name: 'Core Temp',
      type: 'line',
      smooth: true,
      data: transformedData.values,
      lineStyle: { width: 3 },
      markLine: {
        silent: true,
        symbol: 'none',
        lineStyle: {
          color: '#cc0033',
          type: 'solid',
          width: 2
        },
        label: { formatter: 'Critical Alert', position: 'end' },
        data: [
          { yAxis: transformedData.threshold }
        ]
      }
    }
  ]
};
